/* Larger distances use the log2-based encoding; restate it exactly so any
   mutation of the arithmetic is caught. */
__CPROVER_ensures(dist >= 5 ==>
    __CPROVER_return_value ==
        2 * (31 ^ __builtin_clz(dist - 1)) +
